"""Tests for markdown parser round-trip and edge cases."""

import tempfile
from pathlib import Path

import pytest

from beliefs_lib import Claim
from beliefs_lib.parser import (
    append_claim,
    parse_registry,
    serialize_claim,
    serialize_registry,
    update_claim_status,
)

# -- Fixtures --

